"use client";

import { Languages } from "lucide-react";
import type { Locale } from "@/data/invitation";

interface LanguageSwitchProps {
  locale: Locale;
  onToggle: () => void;
  label: string;
}

export function LanguageSwitch({ locale, onToggle, label }: LanguageSwitchProps) {
  const isSpanish = locale === "es";

  return (
    <button
      type="button"
      onClick={onToggle}
      className="group inline-flex items-center gap-3 rounded-full border border-white/80 bg-white/90 p-1.5 pr-4 text-sm font-semibold text-slate-700 shadow-[0_16px_40px_rgba(59,130,246,0.18)] backdrop-blur-xl transition hover:-translate-y-0.5 hover:bg-white"
      aria-label={label}
    >
      <span className={`flex h-9 w-16 items-center rounded-full p-1 transition ${isSpanish ? "bg-sky-600" : "bg-slate-300"}`}>
        <span className={`flex h-7 w-7 items-center justify-center rounded-full bg-white shadow-md transition ${isSpanish ? "translate-x-0" : "translate-x-6"}`}>
          <Languages className="h-4 w-4 text-sky-700" />
        </span>
      </span>
      <span className="flex flex-col items-start leading-none">
        <span className="text-[0.7rem] uppercase tracking-[0.35em] text-slate-400">Idioma</span>
        <span className="mt-1 text-sm font-bold text-slate-800">
          {isSpanish ? "ES" : "EN"}
          <span className="ml-2 text-slate-400">/</span>
          <span className="ml-2 text-slate-500">{isSpanish ? "EN" : "ES"}</span>
        </span>
      </span>
    </button>
  );
}
