import { PhotoPlaceholder } from "@/components/ui/photo-placeholder";

interface PhotosSectionProps {
  locale: Locale;
}

export function PhotosSection({ locale }: PhotosSectionProps) {
  const content = invitationContent[locale];

  return (
    <section className="space-y-6">
      <div>
        <p className="text-xs font-semibold uppercase tracking-[0.35em] text-sky-700">{content.photosIntro}</p>
        <h2 className="mt-2 font-display text-3xl font-black text-slate-900 md:text-4xl">{content.photosTitle}</h2>
      </div>
      <div className="grid gap-6 md:grid-cols-2">
        {content.photos.map((photo) => (
          <PhotoPlaceholder key={photo.title} {...photo} />
        ))}
      </div>
    </section>
  );
}
